+        let stmt = parse_one("INSERT INTO t (x, y) VALUES (1, 2), (3, 4), (5, 6)");
+        if let Statement::Insert(i) = stmt {
+            if let InsertSource::Values(rows) = &i.source {
+                assert_eq!(rows.len(), 3);
+                for row in rows {
+                    assert_eq!(row.len(), 2);
+                }
+            } else {
+                unreachable!("expected Values source");
+            }
+        } else {
